-- FormCoach Database Initialization
-- Run this after creating the database: CREATE DATABASE form_coach DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;

-- 1. User table
CREATE TABLE IF NOT EXISTS sys_user (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    username VARCHAR(50) NOT NULL UNIQUE COMMENT '用户名',
    password VARCHAR(255) NOT NULL COMMENT 'BCrypt加密密码',
    nickname VARCHAR(50) DEFAULT '' COMMENT '昵称',
    avatar VARCHAR(255) DEFAULT '' COMMENT '头像URL',
    height DECIMAL(5,1) DEFAULT NULL COMMENT '身高(cm)',
    weight DECIMAL(5,1) DEFAULT NULL COMMENT '体重(kg)',
    gender TINYINT DEFAULT 0 COMMENT '0未知 1男 2女',
    create_time DATETIME DEFAULT CURRENT_TIMESTAMP,
    update_time DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='用户表';

-- 2. Movement library
CREATE TABLE IF NOT EXISTS coach_movement (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    name VARCHAR(50) NOT NULL COMMENT '动作名称',
    category VARCHAR(50) NOT NULL COMMENT '分类(上肢/下肢/核心)',
    UNIQUE KEY uk_name (name),
    description TEXT COMMENT '动作描述',
    standard_angles JSON COMMENT '标准角度配置',
    tips JSON COMMENT '纠错文案配置',
    image_url VARCHAR(255) DEFAULT '' COMMENT '示范图片',
    video_url VARCHAR(255) DEFAULT '' COMMENT '示范视频',
    create_time DATETIME DEFAULT CURRENT_TIMESTAMP,
    update_time DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='动作库';

-- 3. Training session
CREATE TABLE IF NOT EXISTS coach_training_session (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    user_id BIGINT NOT NULL COMMENT '用户ID',
    movement_id BIGINT NOT NULL COMMENT '动作ID',
    score INT DEFAULT 0 COMMENT '综合评分(0-100)',
    duration_seconds INT DEFAULT 0 COMMENT '训练时长(秒)',
    rep_count INT DEFAULT 0 COMMENT '完成次数',
    error_summary JSON COMMENT '错误汇总JSON',
    avg_angles JSON COMMENT '平均角度JSON',
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    INDEX idx_user_id (user_id),
    INDEX idx_user_movement (user_id, movement_id),
    INDEX idx_created_at (created_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='训练会话';

-- 4. Frame data (optional, mainly store error frames)
CREATE TABLE IF NOT EXISTS coach_frame_data (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    session_id BIGINT NOT NULL COMMENT '训练会话ID',
    frame_index INT NOT NULL COMMENT '帧序号',
    joint_data JSON NOT NULL COMMENT '33个关节点坐标JSON',
    is_error_frame TINYINT DEFAULT 0 COMMENT '是否错误帧',
    error_type VARCHAR(50) DEFAULT '' COMMENT '错误类型',
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    INDEX idx_session_id (session_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='关键帧数据';

-- 5. Angle calculation results
CREATE TABLE IF NOT EXISTS coach_angle_result (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    session_id BIGINT NOT NULL COMMENT '训练会话ID',
    frame_index INT NOT NULL COMMENT '帧序号',
    joint_name VARCHAR(50) NOT NULL COMMENT '关节名称',
    angle_value DECIMAL(6,2) NOT NULL COMMENT '角度值',
    angle_status VARCHAR(10) DEFAULT 'NORMAL' COMMENT 'NORMAL/WARN/ERROR',
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    INDEX idx_session_id (session_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='角度计算结果';

-- 6. User achievements
CREATE TABLE IF NOT EXISTS coach_achievement (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    user_id BIGINT NOT NULL COMMENT '用户ID',
    achievement_type VARCHAR(50) NOT NULL COMMENT '成就类型',
    unlocked_at DATETIME DEFAULT CURRENT_TIMESTAMP COMMENT '解锁时间',
    UNIQUE KEY uk_user_achievement (user_id, achievement_type)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='用户成就';

