INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('深蹲','下肢','双脚与肩同宽，缓慢下蹲至大腿与地面平行，保持腰背挺直。','{"leftKnee": {"min": 80, "max": 100, "jointChain": ["leftHip", "leftKnee", "leftAnkle"]}, "rightKnee": {"min": 80, "max": 100, "jointChain": ["rightHip", "rightKnee", "rightAnkle"]}, "leftHip": {"min": 70, "max": 100, "jointChain": ["leftShoulder", "leftHip", "leftKnee"]}, "rightHip": {"min": 70, "max": 100, "jointChain": ["rightShoulder", "rightHip", "rightKnee"]}, "backAngle": {"min": 60, "max": 90, "jointChain": ["leftShoulder", "leftHip", "leftAnkle"]}, "leftKneeOverToe": {"min": 0, "max": 3, "jointChain": ["leftKnee", "leftAnkle"]}, "rightKneeOverToe": {"min": 0, "max": 3, "jointChain": ["rightKnee", "rightAnkle"]}}','{"kneeOverToe": "重心后移膝盖不要超过脚尖", "kneeValgus": "膝盖不要内扣", "backRound": "挺直腰背不要弓背", "tooDeep": "下蹲过深", "tooShallow": "再蹲低一点", "leanForward": "上身不要太前倾"}');
