INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('鸟狗式','核心','四足跪姿，对侧手脚同时伸展，保持身体稳定。','{"bodyLine": {"min": 170, "max": 180, "jointChain": ["leftShoulder", "leftHip", "leftAnkle"]}, "leftHip": {"min": 70, "max": 100, "jointChain": ["leftShoulder", "leftHip", "leftKnee"]}, "rightHip": {"min": 70, "max": 100, "jointChain": ["rightShoulder", "rightHip", "rightKnee"]}}','{"hipRotate": "骨盆不要旋转", "backArch": "核心收紧", "headUp": "颈部中立"}');
