INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('登山者','核心','俯卧撑姿势，交替提膝向胸，保持核心收紧。','{"leftHip": {"min": 60, "max": 90, "jointChain": ["leftShoulder", "leftHip", "leftKnee"]}, "rightHip": {"min": 60, "max": 90, "jointChain": ["rightShoulder", "rightHip", "rightKnee"]}, "leftKnee": {"min": 70, "max": 100, "jointChain": ["leftHip", "leftKnee", "leftAnkle"]}, "rightKnee": {"min": 70, "max": 100, "jointChain": ["rightHip", "rightKnee", "rightAnkle"]}}','{"hipHigh": "臀部不要抬高", "fastRhythm": "保持匀速", "halfKnee": "膝盖尽量靠近胸部"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('V字卷腹','核心','仰卧，同时抬起上身和双腿，双手触碰脚尖。','{"trunkAngle": {"min": 30, "max": 60, "jointChain": ["leftHip", "leftShoulder", "leftKnee"]}, "kneeAngle": {"min": 150, "max": 170, "jointChain": ["leftHip", "leftKnee", "leftAnkle"]}}','{"halfRep": "充分卷起", "swing": "腹肌发力不借力", "legBend": "腿尽量伸直"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('波比跳','全身','深蹲接俯卧撑接跳跃，连续完成，全身协调发力。','{"leftKnee": {"min": 80, "max": 100, "jointChain": ["leftHip", "leftKnee", "leftAnkle"]}, "rightKnee": {"min": 80, "max": 100, "jointChain": ["rightHip", "rightKnee", "rightAnkle"]}, "leftElbow": {"min": 70, "max": 100, "jointChain": ["leftShoulder", "leftElbow", "leftWrist"]}, "rightElbow": {"min": 70, "max": 100, "jointChain": ["rightShoulder", "rightElbow", "rightWrist"]}}','{"hipSag": "俯卧时身体直线", "halfSquat": "深蹲到位", "landSoft": "跳跃落地缓冲"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('开合跳','全身','并腿站立，跳起分腿，同时双手在头顶击掌，再跳回。','{"leftHip": {"min": 40, "max": 70, "jointChain": ["leftShoulder", "leftHip", "leftKnee"]}, "rightHip": {"min": 40, "max": 70, "jointChain": ["rightShoulder", "rightHip", "rightKnee"]}, "leftElbow": {"min": 140, "max": 180, "jointChain": ["leftShoulder", "leftElbow", "leftWrist"]}, "rightElbow": {"min": 140, "max": 180, "jointChain": ["rightShoulder", "rightElbow", "rightWrist"]}}','{"smallJump": "跳起幅度要大", "armDown": "手臂举过头顶", "landSoft": "落地缓冲"}');;
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('单腿深蹲','下肢','单腿站立，另一腿前伸，缓慢下蹲至支撑大腿与地面平行。','{"leftKnee":{"min":80,"max":100,"jointChain":["leftHip","leftKnee","leftAnkle"]},"leftHip":{"min":70,"max":100,"jointChain":["leftShoulder","leftHip","leftKnee"]},"backAngle":{"min":60,"max":90,"jointChain":["leftShoulder","leftHip","leftAnkle"]}}','{"kneeValgus":"膝盖朝前不要内扣","backRound":"挺直腰背","tooDeep":"控制深度"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('后撤步弓步','下肢','向后跨一步，双腿屈膝下蹲，前腿发力回到起始位。','{"frontKnee":{"min":80,"max":100,"jointChain":["leftHip","leftKnee","leftAnkle"]},"backKnee":{"min":80,"max":100,"jointChain":["rightHip","rightKnee","rightAnkle"]},"backAngle":{"min":70,"max":95,"jointChain":["leftShoulder","leftHip","leftAnkle"]}}','{"kneeOverToe":"前膝不要超过脚尖","leanForward":"上身挺直","balance":"保持平衡"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('交替弓步跳','下肢','弓步姿势，跳起空中交换双腿，落地缓冲。','{"frontKnee":{"min":80,"max":100,"jointChain":["leftHip","leftKnee","leftAnkle"]},"backKnee":{"min":80,"max":100,"jointChain":["rightHip","rightKnee","rightAnkle"]}}','{"landSoft":"落地缓冲","kneeValgus":"膝盖朝前","balance":"控制平衡"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('蛙跳','下肢','深蹲位，双手背后，向前跳跃，落地缓冲。','{"leftKnee":{"min":80,"max":100,"jointChain":["leftHip","leftKnee","leftAnkle"]},"rightKnee":{"min":80,"max":100,"jointChain":["rightHip","rightKnee","rightAnkle"]},"leftHip":{"min":70,"max":100,"jointChain":["leftShoulder","leftHip","leftKnee"]}}','{"landSoft":"落地轻盈","backRound":"挺胸","kneeValgus":"膝盖朝前"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('蟹步走','下肢','四肢撑地，腹部朝上，横向移动。','{"leftElbow":{"min":140,"max":180,"jointChain":["leftShoulder","leftElbow","leftWrist"]},"rightElbow":{"min":140,"max":180,"jointChain":["rightShoulder","rightElbow","rightWrist"]},"leftHip":{"min":140,"max":180,"jointChain":["leftShoulder","leftHip","leftKnee"]}}','{"hipSag":"臀部不要下沉","slowMove":"控制速度","core":"核心收紧"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('引体向上','上肢','双手正握单杠，背阔肌发力将身体拉起至下巴过杠。','{"leftElbow":{"min":30,"max":50,"jointChain":["leftShoulder","leftElbow","leftWrist"]},"rightElbow":{"min":30,"max":50,"jointChain":["rightShoulder","rightElbow","rightWrist"]},"shoulderAngle":{"min":140,"max":180,"jointChain":["leftHip","leftShoulder","leftElbow"]}}','{"swing":"不要摆动借力","fullROM":"下巴过杠","halfRep":"手臂下放至伸直"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('俯身划船','上肢','屈髋俯身，背部挺直，将重物沿大腿拉向腹部。','{"leftElbow":{"min":50,"max":80,"jointChain":["leftShoulder","leftElbow","leftWrist"]},"rightElbow":{"min":50,"max":80,"jointChain":["rightShoulder","rightElbow","rightWrist"]},"backAngle":{"min":50,"max":80,"jointChain":["leftShoulder","leftHip","leftAnkle"]}}','{"backRound":"背部挺直","swing":"控制速度","elbowIn":"手肘贴近身体"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('蜘蛛人俯卧撑','上肢','俯卧撑位，屈肘时一侧膝盖向同侧手肘靠近。','{"leftElbow":{"min":70,"max":100,"jointChain":["leftShoulder","leftElbow","leftWrist"]},"rightElbow":{"min":70,"max":100,"jointChain":["rightShoulder","rightElbow","rightWrist"]},"leftHip":{"min":60,"max":90,"jointChain":["leftShoulder","leftHip","leftKnee"]}}','{"hipSag":"身体保持直线","kneeToElbow":"膝盖靠近手肘","slowMove":"控制节奏"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('仰卧抬腿','核心','仰卧，双腿并拢伸直，腹肌发力抬起至垂直地面。','{"leftHip":{"min":70,"max":100,"jointChain":["leftShoulder","leftHip","leftKnee"]},"rightHip":{"min":70,"max":100,"jointChain":["rightShoulder","rightHip","rightKnee"]},"kneeAngle":{"min":150,"max":180,"jointChain":["leftHip","leftKnee","leftAnkle"]}}','{"swing":"腹肌发力不借力","legBend":"腿尽量伸直","backArch":"下背贴地"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('剪刀腿','核心','仰卧，双腿伸直交替上下交叉摆动。','{"leftHip":{"min":60,"max":90,"jointChain":["leftShoulder","leftHip","leftKnee"]},"rightHip":{"min":60,"max":90,"jointChain":["rightShoulder","rightHip","rightKnee"]}}','{"backArch":"下背贴地","fastMove":"控制速度","legStraight":"双腿伸直"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('交替触踝','核心','仰卧屈膝，上身微抬，左右交替触摸脚踝。','{"trunkAngle":{"min":20,"max":50,"jointChain":["leftHip","leftShoulder","leftKnee"]}}','{"neckPull":"颈部放松","sideBend":"侧腹发力","breath":"配合呼吸"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('平板交替抬手','核心','平板支撑位，交替向前伸直手臂，保持身体稳定。','{"bodyLine":{"min":170,"max":180,"jointChain":["leftShoulder","leftHip","leftAnkle"]},"leftElbow":{"min":160,"max":180,"jointChain":["leftShoulder","leftElbow","leftWrist"]}}','{"hipRotate":"骨盆保持稳定","slowMove":"控制速度","core":"核心收紧"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('猫牛式','拉伸','四足跪姿，吸气时弓背低头，呼气时塌腰抬头。','{"backAngle":{"min":40,"max":80,"jointChain":["leftShoulder","leftHip","leftAnkle"]},"trunkAngle":{"min":40,"max":80,"jointChain":["leftHip","leftShoulder","leftKnee"]}}','{"slowMove":"配合呼吸缓慢移动","fullROM":"完整活动范围","relax":"肩颈放松"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('下犬式','拉伸','从平板支撑位推臀向上，身体呈倒V形，脚跟下压。','{"bodyLine":{"min":130,"max":160,"jointChain":["leftShoulder","leftHip","leftAnkle"]},"hipAngle":{"min":80,"max":110,"jointChain":["leftShoulder","leftHip","leftKnee"]}}','{"heelsDown":"脚跟向地面下压","backStraight":"背部挺直","headRelax":"头部放松"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('婴儿式','拉伸','跪坐，上身前倾，额头贴地，双臂前伸或放于体侧。','{"hipAngle":{"min":30,"max":60,"jointChain":["leftShoulder","leftHip","leftKnee"]},"kneeAngle":{"min":60,"max":90,"jointChain":["leftHip","leftKnee","leftAnkle"]}}','{"relax":"全身放松","breath":"深呼吸","hipsBack":"臀部坐向脚跟"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('肩部拉伸','拉伸','一侧手臂横过胸前，另一手辅助拉伸。','{"leftElbow":{"min":150,"max":180,"jointChain":["leftShoulder","leftElbow","leftWrist"]},"shoulderAngle":{"min":70,"max":100,"jointChain":["leftHip","leftShoulder","leftElbow"]}}','{"gentle":"轻柔拉伸","noPain":"不要拉到疼痛","hold":"保持15-30秒"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('站立体前屈','拉伸','站立位，缓慢向前弯曲，双手触地或小腿。','{"backAngle":{"min":30,"max":60,"jointChain":["leftShoulder","leftHip","leftAnkle"]},"kneeAngle":{"min":150,"max":180,"jointChain":["leftHip","leftKnee","leftAnkle"]}}','{"kneeBend":"膝盖微屈","slowMove":"缓慢下弯","relax":"头部放松"}');
INSERT IGNORE INTO coach_movement (name, category, description, standard_angles, tips) VALUES ('上犬式','拉伸','俯卧，双手推地，上身抬起，大腿离地。','{"backAngle":{"min":120,"max":150,"jointChain":["leftShoulder","leftHip","leftAnkle"]},"leftElbow":{"min":150,"max":180,"jointChain":["leftShoulder","leftElbow","leftWrist"]}}','{"shouldersDown":"肩膀下沉","chestOpen":"胸腔打开","legsActive":"大腿收紧"}');;
